import{_ as o,o as a,c,ag as t}from"./chunks/framework.CTpQozEL.js";const u=JSON.parse('{"title":"프레전스","description":"OpenClaw 프레전스 항목이 생성, 병합, 표시되는 방법","frontmatter":{"title":"프레전스","description":"OpenClaw 프레전스 항목이 생성, 병합, 표시되는 방법"},"headers":[],"relativePath":"concepts/presence.md","filePath":"concepts/presence.md","lastUpdated":null}'),d={name:"concepts/presence.md"};function n(i,e,l,s,r,h){return a(),c("div",null,[...e[0]||(e[0]=[t('<h1 id="프레전스" tabindex="-1">프레전스 <a class="header-anchor" href="#프레전스" aria-label="Permalink to &quot;프레전스&quot;">​</a></h1><p>OpenClaw &quot;프레전스&quot;는 다음의 가볍고 최선형 뷰입니다:</p><ul><li><strong>게이트웨이</strong> 자체, 그리고</li><li><strong>게이트웨이에 연결된 클라이언트</strong> (Mac 앱, WebChat, CLI 등)</li></ul><p>프레전스는 주로 macOS 앱의 <strong>Instances</strong> 탭을 렌더링하고 빠른 운영자 가시성을 제공하는 데 사용됩니다.</p><h2 id="프레전스-필드-표시되는-항목" tabindex="-1">프레전스 필드 (표시되는 항목) <a class="header-anchor" href="#프레전스-필드-표시되는-항목" aria-label="Permalink to &quot;프레전스 필드 (표시되는 항목)&quot;">​</a></h2><p>프레전스 항목은 다음과 같은 필드를 가진 구조화된 객체입니다:</p><ul><li><code>instanceId</code> (선택적이지만 강력히 권장): 안정적인 클라이언트 ID (일반적으로 <code>connect.client.instanceId</code>)</li><li><code>host</code>: 사람이 읽기 쉬운 호스트 이름</li><li><code>ip</code>: 최선형 IP 주소</li><li><code>version</code>: 클라이언트 버전 문자열</li><li><code>deviceFamily</code> / <code>modelIdentifier</code>: 하드웨어 힌트</li><li><code>mode</code>: <code>ui</code>, <code>webchat</code>, <code>cli</code>, <code>backend</code>, <code>probe</code>, <code>test</code>, <code>node</code>, ...</li><li><code>lastInputSeconds</code>: &quot;마지막 사용자 입력 이후 초&quot; (알 수 있는 경우)</li><li><code>reason</code>: <code>self</code>, <code>connect</code>, <code>node-connected</code>, <code>periodic</code>, ...</li><li><code>ts</code>: 마지막 업데이트 타임스탬프 (에포크 이후 밀리초)</li></ul><h2 id="생산자-프레전스가-오는-곳" tabindex="-1">생산자 (프레전스가 오는 곳) <a class="header-anchor" href="#생산자-프레전스가-오는-곳" aria-label="Permalink to &quot;생산자 (프레전스가 오는 곳)&quot;">​</a></h2><p>프레전스 항목은 여러 소스에서 생성되고 <strong>병합</strong>됩니다.</p><h3 id="_1-게이트웨이-자체-항목" tabindex="-1">1) 게이트웨이 자체 항목 <a class="header-anchor" href="#_1-게이트웨이-자체-항목" aria-label="Permalink to &quot;1) 게이트웨이 자체 항목&quot;">​</a></h3><p>게이트웨이는 시작 시 항상 &quot;self&quot; 항목을 시드합니다. 따라서 클라이언트가 연결되기 전에도 UI는 게이트웨이 호스트를 표시합니다.</p><h3 id="_2-websocket-연결" tabindex="-1">2) WebSocket 연결 <a class="header-anchor" href="#_2-websocket-연결" aria-label="Permalink to &quot;2) WebSocket 연결&quot;">​</a></h3><p>모든 WS 클라이언트는 <code>connect</code> 요청으로 시작합니다. 성공적인 핸드셰이크 시 게이트웨이는 해당 연결에 대한 프레전스 항목을 업서트합니다.</p><h4 id="일회성-cli-커맨드가-표시되지-않는-이유" tabindex="-1">일회성 CLI 커맨드가 표시되지 않는 이유 <a class="header-anchor" href="#일회성-cli-커맨드가-표시되지-않는-이유" aria-label="Permalink to &quot;일회성 CLI 커맨드가 표시되지 않는 이유&quot;">​</a></h4><p>CLI는 종종 짧은 일회성 커맨드를 위해 연결합니다. Instances 목록을 스팸으로 채우지 않기 위해 <code>client.mode === &quot;cli&quot;</code>는 프레전스 항목으로 변환되지 <strong>않습니다</strong>.</p><h3 id="_3-system-event-비콘" tabindex="-1">3) <code>system-event</code> 비콘 <a class="header-anchor" href="#_3-system-event-비콘" aria-label="Permalink to &quot;3) `system-event` 비콘&quot;">​</a></h3><p>클라이언트는 <code>system-event</code> 메서드를 통해 더 풍부한 주기적 비콘을 보낼 수 있습니다. Mac 앱은 이를 사용하여 호스트 이름, IP, <code>lastInputSeconds</code>를 보고합니다.</p><h3 id="_4-노드-연결-역할-node" tabindex="-1">4) 노드 연결 (역할: node) <a class="header-anchor" href="#_4-노드-연결-역할-node" aria-label="Permalink to &quot;4) 노드 연결 (역할: node)&quot;">​</a></h3><p>노드가 <code>role: node</code>로 게이트웨이 WebSocket을 통해 연결되면, 게이트웨이는 해당 노드에 대한 프레전스 항목을 업서트합니다 (다른 WS 클라이언트와 동일한 흐름).</p><h2 id="병합-중복-제거-규칙-instanceid가-중요한-이유" tabindex="-1">병합 + 중복 제거 규칙 (<code>instanceId</code>가 중요한 이유) <a class="header-anchor" href="#병합-중복-제거-규칙-instanceid가-중요한-이유" aria-label="Permalink to &quot;병합 + 중복 제거 규칙 (`instanceId`가 중요한 이유)&quot;">​</a></h2><p>프레전스 항목은 단일 인메모리 맵에 저장됩니다:</p><ul><li>항목은 <strong>프레전스 키</strong>로 키가 지정됩니다.</li><li>최상의 키는 재시작 후에도 살아남는 안정적인 <code>instanceId</code> (<code>connect.client.instanceId</code>에서)입니다.</li><li>키는 대소문자를 구분하지 않습니다.</li></ul><p>클라이언트가 안정적인 <code>instanceId</code> 없이 재연결하면 <strong>중복</strong> 행으로 표시될 수 있습니다.</p><h2 id="ttl-및-제한된-크기" tabindex="-1">TTL 및 제한된 크기 <a class="header-anchor" href="#ttl-및-제한된-크기" aria-label="Permalink to &quot;TTL 및 제한된 크기&quot;">​</a></h2><p>프레전스는 의도적으로 일시적입니다:</p><ul><li><strong>TTL:</strong> 5분보다 오래된 항목은 정리됩니다</li><li><strong>최대 항목:</strong> 200개 (가장 오래된 것 먼저 삭제)</li></ul><p>이는 목록을 신선하게 유지하고 무제한 메모리 증가를 방지합니다.</p><h2 id="원격-터널-주의사항-루프백-ip" tabindex="-1">원격/터널 주의사항 (루프백 IP) <a class="header-anchor" href="#원격-터널-주의사항-루프백-ip" aria-label="Permalink to &quot;원격/터널 주의사항 (루프백 IP)&quot;">​</a></h2><p>클라이언트가 SSH 터널 / 로컬 포트 포워드를 통해 연결하면 게이트웨이는 원격 주소를 <code>127.0.0.1</code>로 볼 수 있습니다. 좋은 클라이언트 보고 IP를 덮어쓰지 않기 위해 루프백 원격 주소는 무시됩니다.</p><h2 id="소비자" tabindex="-1">소비자 <a class="header-anchor" href="#소비자" aria-label="Permalink to &quot;소비자&quot;">​</a></h2><h3 id="macos-instances-탭" tabindex="-1">macOS Instances 탭 <a class="header-anchor" href="#macos-instances-탭" aria-label="Permalink to &quot;macOS Instances 탭&quot;">​</a></h3><p>macOS 앱은 <code>system-presence</code> 출력을 렌더링하고 마지막 업데이트 나이에 따라 작은 상태 표시기 (Active/Idle/Stale)를 적용합니다.</p><h2 id="디버깅-팁" tabindex="-1">디버깅 팁 <a class="header-anchor" href="#디버깅-팁" aria-label="Permalink to &quot;디버깅 팁&quot;">​</a></h2><ul><li>원시 목록을 보려면 게이트웨이에 대해 <code>system-presence</code>를 호출하십시오.</li><li>중복이 보이는 경우: <ul><li>클라이언트가 핸드셰이크에서 안정적인 <code>client.instanceId</code>를 보내는지 확인하십시오</li><li>주기적 비콘이 동일한 <code>instanceId</code>를 사용하는지 확인하십시오</li><li>연결 유래 항목에 <code>instanceId</code>가 누락되어 있는지 확인하십시오 (중복은 예상됨)</li></ul></li></ul>',34)])])}const m=o(d,[["render",n]]);export{u as __pageData,m as default};
